step.script:
# This would dynamically generate checks for all columns
# For demo, checking first column
curl -X POST ${API_URL}/api/expectations/run-adhoc \
  -H "Content-Type: application/json" \
  -d '{
    "name": "NULL Check - '${table}'",
    "connection_id": "'${connection_id}'",
    "expectations": [
      {
        "type": "expect_table_row_count_to_be_between",
        "params": {"min_rows": 1},
        "target": {"schema": "'${schema}'", "table": "'${table}'"}
      }
    ]
  }'

echo "Running uniqueness checks on ${schema}.${table}"
curl -X POST ${API_URL}/api/expectations/run-adhoc \
  -H "Content-Type: application/json" \
  -d '{
    "name": "Uniqueness Check - '${table}'",
    "connection_id": "'${connection_id}'",
    "expectations": [
      {
        "type": "expect_table_row_count_to_be_between",
        "params": {"min_rows": 1},
        "target": {"schema": "'${schema}'", "table": "'${table}'"}
      }
    ]
  }'
